import React from 'react';
import { Card, Stack, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const { 
    city, 
    temperature, 
    condition, 
    humidity, 
    windSpeed, 
    unit = '°C', 
    forecast = [] 
  } = props;

  return (
    <Card shadow="md" padding={24} style={{ maxWidth: '400px' }}>
      <Stack gap={24}>
        {/* Main Info */}
        <Stack gap={4}>
          <Heading level={2}>{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{condition}</Text>
        </Stack>

        <Heading level={1} color="var(--ggui-color-primary-600)">
          {temperature}{unit}
        </Heading>

        {/* Stats */}
        <Stack direction="horizontal" gap={16} justify="between">
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
            <Text variant="body" weight="semibold">{humidity}%</Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
            <Text variant="body" weight="semibold">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={0} />

        {/* Forecast */}
        <Stack direction="horizontal" gap={16} justify="between">
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="label">{item.day ?? '---'}</Text>
              <Text size="2xl">{item.icon ?? '?'}</Text>
              <Stack direction="horizontal" gap={4}>
                <Text variant="bodySmall" weight="bold">{item.high}°</Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{item.low}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  useEffect(() => {
    const handleAgentData = (event: any) => {
      console.log('Agent data received:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const isStepValid = useMemo(() => {
    switch (step) {
      case 0:
        return formData.name.trim() !== '' && emailRegex.test(formData.email);
      case 1:
        return formData.satisfaction > 0;
      default:
        return true;
    }
  }, [step, formData]);

  const updateField = (field: keyof typeof formData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = () => {
    setIsSubmitting(true);
    props.onSubmit(formData);
  };

  const renderStep = () => {
    switch (step) {
      case 0:
        return (
          <Stack gap={16}>
            <Input
              label="Full Name"
              required
              value={formData.name}
              onChange={(v) => updateField('name', v)}
            />
            <Input
              label="Email Address"
              type="email"
              required
              value={formData.email}
              onChange={(v) => updateField('email', v)}
              error={formData.email && !emailRegex.test(formData.email) ? 'Please enter a valid email address' : undefined}
            />
          </Stack>
        );
      case 1:
        return (
          <RadioGroup
            label="How satisfied are you with our service?"
            value={formData.satisfaction > 0 ? formData.satisfaction.toString() : ''}
            onChange={(v) => updateField('satisfaction', Number(v))}
            options={props.satisfactionLabels.map((label, i) => ({
              value: (i + 1).toString(),
              label: label,
            }))}
          />
        );
      case 2:
        return (
          <Stack gap={12}>
            <Text variant="label">Select features of interest</Text>
            {props.featureOptions.map((feat) => (
              <Checkbox
                key={feat}
                label={feat}
                checked={formData.features.includes(feat)}
                onChange={(checked) => {
                  const newFeatures = checked
                    ? [...formData.features, feat]
                    : formData.features.filter((f) => f !== feat);
                  updateField('features', newFeatures);
                }}
              />
            ))}
          </Stack>
        );
      case 3:
        return (
          <Stack gap={16}>
            <TextArea
              label="Additional Comments (Optional)"
              value={formData.comments}
              onChange={(v) => updateField('comments', v)}
              maxLength={500}
              showCount
              rows={4}
            />
            <Divider />
            <Stack gap={8}>
              <Heading level={4}>Review Your Answers</Heading>
              <Text><strong>Name:</strong> {formData.name}</Text>
              <Text><strong>Email:</strong> {formData.email}</Text>
              <Text><strong>Satisfaction:</strong> {formData.satisfaction > 0 ? props.satisfactionLabels[formData.satisfaction - 1] : 'Not set'}</Text>
              <Text><strong>Features:</strong> {formData.features.length ? formData.features.join(', ') : 'None selected'}</Text>
              <Text><strong>Comments:</strong> {formData.comments || 'No comments provided'}</Text>
            </Stack>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="md" padding={24}>
      <Card padding={24} shadow="md">
        <Stack gap={24}>
          <Stack gap={8}>
            <Heading level={3}>Customer Satisfaction Survey</Heading>
            <Progress value={((step + 1) / 4) * 100} size="md" />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step + 1} of 4
            </Text>
          </Stack>

          <Box paddingY={8}>
            {renderStep()}
          </Box>

          <Stack direction="horizontal" gap={16} justify="end">
            {step > 0 && (
              <Button variant="ghost" onClick={() => setStep((s) => s - 1)}>
                Back
              </Button>
            )}
            {step < 3 ? (
              <Button onClick={() => setStep((s) => s + 1)} disabled={!isStepValid}>
                Next
              </Button>
            ) : (
              <Button 
                variant="primary" 
                onClick={handleSubmit} 
                loading={isSubmitting}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Divider,
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Props {
  tasks: Array<Task>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate: (payload: { action: string; taskId: string; data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [tasks, setTasks] = useState<Task[]>(props.tasks ?? []);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTask, setNewTask] = useState<{ title: string; priority: 'low' | 'medium' | 'high' }>({
    title: '',
    priority: 'medium',
  });

  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail) setTasks(event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  useEffect(() => {
    setTasks(props.tasks ?? []);
  }, [props.tasks]);

  const handleUpdate = (action: string, taskId: string, data: any) => {
    props.onTaskUpdate({ action, taskId, data });
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, ...data } : t)));
  };

  const handleCreate = (colId: string) => {
    if (!newTask.title.trim()) return;
    const newId = Math.random().toString(36).substring(2, 9);
    const data = { ...newTask, column: colId, assignee: 'ME' };
    props.onTaskUpdate({ action: 'create', taskId: newId, data });
    setTasks([...tasks, { id: newId, ...data }]);
    setAddingTo(null);
    setNewTask({ title: '', priority: 'medium' });
  };

  const getPriorityVariant = (priority: string | undefined): 'info' | 'warning' | 'error' | 'default' => {
    switch (priority) {
      case 'low': return 'info';
      case 'medium': return 'warning';
      case 'high': return 'error';
      default: return 'default';
    }
  };

  const doneColumnId = props.columns.find((c) => c.name?.toLowerCase() === 'done')?.id;
  const totalTasks = tasks.length;
  const doneTasks = tasks.filter((t) => t.column === doneColumnId).length;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Box
          padding="var(--ggui-spacing-4, 16px)"
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Heading level={2}>Task Board</Heading>
          <Text variant="bodySmall">Total Tasks: {totalTasks} | Completed: {doneTasks}</Text>
        </Box>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="start" wrap={true}>
          {props.columns.map((col) => (
            <Box
              key={col.id}
              padding="var(--ggui-spacing-4, 16px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
              style={{ minWidth: '300px', flex: 1 }}
            >
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={3}>
                  {col.name} ({tasks.filter((t) => t.column === col.id).length})
                </Heading>

                <Stack gap="var(--ggui-spacing-2, 8px)">
                  {tasks.filter((t) => t.column === col.id).map((task) => (
                    <Card key={task.id} padding="var(--ggui-spacing-4, 16px)" shadow="sm" radius="md">
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        <Heading level={6}>{task.title}</Heading>
                        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                          <Badge variant={getPriorityVariant(task.priority)}>{task.priority ?? 'medium'}</Badge>
                          {task.assignee && <Avatar name={task.assignee} size={24} />}
                          {task.dueDate && <Text variant="caption">Due: {task.dueDate}</Text>}
                        </Stack>
                        <Select
                          label="Move task"
                          value={task.column ?? ''}
                          onChange={(val) => handleUpdate('move', task.id!, { column: val })}
                          options={props.columns.map((c) => ({ value: c.id!, label: c.name! }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addingTo === col.id ? (
                  <Card padding="var(--ggui-spacing-4, 16px)" shadow="sm" radius="md">
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Input
                        label="Task Title"
                        value={newTask.title}
                        onChange={(val) => setNewTask({ ...newTask, title: val })}
                      />
                      <Select
                        label="Priority Level"
                        value={newTask.priority}
                        onChange={(val) => setNewTask({ ...newTask, priority: val as any })}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Button onClick={() => handleCreate(col.id!)} disabled={!newTask.title.trim()}>Create Task</Button>
                      <Button variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" onClick={() => setAddingTo(col.id!)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Card, Box, Text, Heading, Input, Divider } from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const getCategoryColor = (category?: string) => {
  switch (category?.toLowerCase()) {
    case 'alkali': return 'var(--ggui-color-primary-200)';
    case 'nonmetal': return 'var(--ggui-color-success-100)';
    case 'noble-gas': return 'var(--ggui-color-info-100)';
    case 'halogen': return 'var(--ggui-color-warning-100)';
    case 'transition-metal': return 'var(--ggui-color-container)';
    default: return 'var(--ggui-color-surfaceVariant)';
  }
};

export default function GeneratedComponent(props: Props) {
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [props.elements, searchQuery]);

  const categories = useMemo(() => Array.from(new Set(props.elements.map((e) => e.category))), [props.elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={1}>Periodic Table</Heading>

        <Input
          label="Search Elements"
          type="search"
          placeholder="Enter symbol or name..."
          value={searchQuery}
          onChange={(val) => setSearchQuery(val)}
        />

        <Box style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, 1fr)',
          gap: 'var(--ggui-spacing-1)',
          marginTop: 'var(--ggui-spacing-4)'
        }}>
          {props.elements.map((el) => {
            const isMatch = filteredElements.some(f => f.atomicNumber === el.atomicNumber);
            return (
              <Box
                key={el.atomicNumber}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  opacity: isMatch ? 1 : 0.2,
                  transition: 'opacity 200ms ease',
                }}
              >
                <div
                  role="button"
                  tabIndex={0}
                  aria-label={`Element: ${el.name} (${el.symbol})`}
                  onKeyDown={(e) => e.key === 'Enter' && setSelectedElement(el)}
                  onClick={() => setSelectedElement(el)}
                  style={{ height: '100%', outline: 'none', cursor: 'pointer' }}
                >
                  <Card
                    padding="var(--ggui-spacing-1)"
                    radius="sm"
                    style={{
                      backgroundColor: getCategoryColor(el.category),
                      height: '100%',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      justifyContent: 'center',
                      transition: 'transform 200ms ease'
                    }}
                  >
                    <Text variant="caption">{el.atomicNumber}</Text>
                    <Text variant="bodyLarge" weight="bold" align="center">{el.symbol}</Text>
                  </Card>
                </div>
              </Box>
            );
          })}
        </Box>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
          {categories.map(cat => (
            <Stack key={cat ?? 'unknown'} direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Box style={{ width: 16, height: 16, backgroundColor: getCategoryColor(cat) }} borderRadius={4} />
              <Text variant="caption">{cat ?? 'Unknown'}</Text>
            </Stack>
          ))}
        </Stack>

        <Divider margin="var(--ggui-spacing-4)" />

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)">
            <Heading level={3}>{selectedElement.name}</Heading>
            <Stack gap="var(--ggui-spacing-2)" style={{ marginTop: 'var(--ggui-spacing-4)' }}>
              <Text variant="body"><strong>Symbol:</strong> {selectedElement.symbol}</Text>
              <Text variant="body"><strong>Atomic Number:</strong> {selectedElement.atomicNumber}</Text>
              <Text variant="body"><strong>Atomic Weight:</strong> {selectedElement.atomicWeight}</Text>
              <Text variant="body"><strong>Category:</strong> {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Heading, Input, Button, Box, Divider, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback for sending a message */
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [messages, setMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setMessages(props.messages);
  }, [props.messages]);

  useEffect(() => {
    const handleIncoming = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail) {
        setMessages((prev) => [...prev, customEvent.detail]);
      }
    };
    window.addEventListener('ggui:agent-data', handleIncoming);
    return () => window.removeEventListener('ggui:agent-data', handleIncoming);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const sendMessage = () => {
    if (!inputValue.trim()) return;
    const payload = {
      text: inputValue,
      timestamp: new Date().toISOString(),
    };
    props.onSendMessage(payload);
    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') sendMessage();
  };

  return (
    <Card 
      padding={0} 
      shadow="md" 
      radius="lg" 
      border={true}
      style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        height: '600px', 
        width: '100%', 
        maxWidth: '600px', 
        overflow: 'hidden', 
        background: 'var(--ggui-color-surface)' 
      }}
    >
      <Box paddingX="var(--ggui-spacing-4, 16px)" paddingY="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={3}>{props.title}</Heading>
          {props.participantCount !== undefined && (
            <Badge variant="secondary" size="sm">{props.participantCount} participants</Badge>
          )}
        </Stack>
      </Box>
      <Divider />

      <Box 
        padding="var(--ggui-spacing-4, 16px)" 
        style={{ flex: 1, overflowY: 'auto' }}
      >
        <div ref={scrollRef}>
          <Stack gap="var(--ggui-spacing-4, 16px)">
            {messages.map((msg, idx) => {
              const isOwn = msg.sender === props.currentUser;
              return (
                <Stack 
                  key={idx} 
                  align={isOwn ? 'end' : 'start'} 
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  <Box 
                    paddingX="var(--ggui-spacing-4, 16px)" 
                    paddingY="var(--ggui-spacing-2, 8px)" 
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                  >
                    <Text color={isOwn ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}>
                      {msg.text}
                    </Text>
                  </Box>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {msg.sender} • {msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                  </Text>
                </Stack>
              );
            })}
          </Stack>
        </div>
      </Box>

      <Divider />
      <Box padding="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end">
          <div style={{ flex: 1 }}>
            <Input 
              label="New Message"
              value={inputValue} 
              onChange={(val) => setInputValue(val)} 
              onKeyDown={handleKeyDown}
              placeholder="Type a message..."
            />
          </div>
          <Button 
            variant="primary" 
            onClick={sendMessage} 
            disabled={inputValue.trim().length === 0}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Stack, 
  Card, 
  Heading, 
  Text, 
  Box, 
  Icon, 
  Spinner 
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: Array<Stock>;
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [displayStocks, setDisplayStocks] = useState<Stock[]>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);

  useEffect(() => {
    const handleData = (event: any) => {
      const { data, timestamp } = event.detail;
      if (Array.isArray(data)) setDisplayStocks(data);
      if (timestamp) setLastUpdated(timestamp);
    };

    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  if (!displayStocks || displayStocks.length === 0) {
    return (
      <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
        <Stack align="center" gap="var(--ggui-spacing-4, 16px)">
          <Spinner size={32} />
          <Text color="var(--ggui-color-onSurfaceVariant)">Connecting to market feed...</Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={2}>Market Watch</Heading>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Last Updated: {lastUpdated ?? 'N/A'}
          </Text>
        </Stack>

        <CardGrid columns={{ sm: 1, md: 3 }} gap="var(--ggui-spacing-4, 16px)">
          {displayStocks.map((stock, index) => {
            const valChange = stock.change ?? 0;
            const isPositive = valChange >= 0;
            const statusColor = isPositive 
              ? 'var(--ggui-color-success)' 
              : 'var(--ggui-color-error)';

            const symbol = stock.symbol ?? '---';
            const price = stock.price ?? 0;
            const change = Math.abs(valChange);
            const percent = Math.abs(stock.changePercent ?? 0);

            return (
              <Card 
                key={stock.symbol ?? index} 
                padding="var(--ggui-spacing-4, 16px)"
                radius="lg"
                shadow="sm"
                aria-label={`Stock ticker for ${symbol}`}
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={3}>{symbol}</Heading>
                    <Text variant="bodyLarge" weight="bold">
                      ${price.toFixed(2)}
                    </Text>
                  </Stack>

                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {stock.name ?? 'Unknown Company'}
                  </Text>

                  <Box>
                    <Stack direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                      <Icon 
                        name={isPositive ? 'chevron-up' : 'chevron-down'} 
                        size={16} 
                        color={statusColor} 
                      />
                      <span aria-live="polite">
                        <Text variant="bodySmall" weight="medium" color={statusColor}>
                          {change.toFixed(2)} ({percent.toFixed(2)}%)
                        </Text>
                      </span>
                    </Stack>
                  </Box>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Checkbox,
  Toggle,
  Progress,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? ''),
    role: props.initialProfile?.role ?? (props.roleOptions[0] ?? ''),
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  useEffect(() => {
    const handleAgentData = (e: any) => {
      if (e.detail) {
        setFormData((prev) => ({ ...prev, ...e.detail }));
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const isEmailValid = (email: string) => /\S+@\S+\.\S+/.test(email);

  const canProceed = () => {
    if (step === 1) return formData.name.length > 0 && isEmailValid(formData.email);
    if (step === 2) return formData.role.length > 0;
    return true;
  };

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));
  const handleComplete = () => props.onComplete?.(formData);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="lg">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Text variant="label">Step {step} of 3</Text>
            <Progress value={(step / 3) * 100} max={100} variant="default" size="md" />
          </Stack>

          <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={3}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={formData.name}
                  onChange={(v) => setFormData({ ...formData, name: v })}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  value={formData.email}
                  onChange={(v) => setFormData({ ...formData, email: v })}
                  required
                  error={formData.email && !isEmailValid(formData.email) ? 'Invalid email format' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text variant="label">Avatar Selection</Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                    {props.avatarOptions.map((emoji) => (
                      <Button
                        key={emoji}
                        variant={formData.avatar === emoji ? 'primary' : 'secondary'}
                        onPress={() => setFormData({ ...formData, avatar: emoji })}
                      >
                        {emoji}
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={3}>Preferences</Heading>
                <Select
                  label="Role"
                  value={formData.role}
                  onChange={(v) => setFormData({ ...formData, role: v })}
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                  required
                />
                <Checkbox
                  label="Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(v) => setFormData({ ...formData, emailNotifications: v })}
                />
                <Toggle
                  label={`Theme: ${formData.theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={formData.theme === 'dark'}
                  onChange={(v) => setFormData({ ...formData, theme: v ? 'dark' : 'light' })}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={3}>Review & Confirm</Heading>
                <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding="var(--ggui-spacing-4, 16px)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text><strong>Name:</strong> {formData.name}</Text>
                    <Text><strong>Email:</strong> {formData.email}</Text>
                    <Text><strong>Avatar:</strong> {formData.avatar}</Text>
                    <Text><strong>Role:</strong> {formData.role}</Text>
                    <Text><strong>Notifications:</strong> {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                    <Text><strong>Theme:</strong> {formData.theme}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-2, 8px)" />

          <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" justify="end">
            <Button
              variant="ghost"
              onPress={handleBack}
              disabled={step === 1}
            >
              Go Back
            </Button>
            {step < 3 ? (
              <Button onPress={handleNext} disabled={!canProceed()}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onPress={handleComplete}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
